function imgOut = fCmrNoiseV01(img,cmrPeak,cmrThre,anlThre,cmrSig,sttNmb)%% add camera noise and threshold%% imgOut = fCmrNoiseV01(img,cmrThre,cmrSig,sttNmb)% imgOut: output image%% img:  input image% cmrPeak peak count of the image% cmrThre: camera threshold% cmrSig: camera noise in sigma% sttNmb: number of image for averaging%%% Written by Kei Nakamura% % 2014/7/28 ver.1: Created %% used in% fBllFrgSim4FitV01%% main bodyimg = (cmrThre+cmrPeak)*img/max(max(img));  % normalized to ccd count+threimgOut = img*0;  % allocationimgP = imgOut;  % allocationfor ii=1:sttNmb    imgP(:,:) = cmrSig*randn(size(img)) + img;      % add rms noise, image for process    imgP(:,:) = imgP - cmrThre;   % subtract camera threshold    imgP(:,:) = imgP.*(imgP>=0);    % take negative away    imgOut(:,:) = imgOut + imgP;endimgOut(:,:) = imgOut/sttNmb;   imgOut(:,:) = imgOut.*(imgOut>=anlThre);  % analytical threshold
